    private readonly Dictionary<int, List<int>> _ratings = new();
    private int _nextId;

    public RecipeService()
    {
        _recipes = new List<Recipe>
        {
            new() { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Ingredients = "Pizza dough, San Marzano tomatoes, Fresh mozzarella, Fresh basil, Olive oil, Salt",
                Steps = "1. Preheat oven to 475°F.\n2. Roll out dough on floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute over sauce.\n5. Bake 10-12 minutes until crust is golden.\n6. Top with fresh basil and drizzle olive oil." },
            new() { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Ingredients = "Spaghetti, Guanciale, Eggs, Pecorino Romano, Black pepper",
                Steps = "1. Cook spaghetti in salted water until al dente.\n2. Crisp guanciale in a pan.\n3. Whisk eggs with grated pecorino and pepper.\n4. Toss hot pasta with guanciale off heat.\n5. Stir in egg mixture quickly to create creamy sauce.\n6. Serve immediately with extra pecorino." },
            new() { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Ingredients = "Chicken thighs, Yogurt, Garam masala, Cumin, Tomato sauce, Heavy cream, Garlic, Ginger, Onion",
                Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomato sauce and simmer 15 minutes.\n5. Stir in cream and garam masala.\n6. Add chicken pieces and simmer 10 minutes.\n7. Serve with basmati rice or naan." },
            new() { Id = 4, Title = "Vegetable Pad Thai", Category = "Thai",
                Ingredients = "Rice noodles, Tofu, Bean sprouts, Eggs, Peanuts, Lime, Tamarind paste, Fish sauce, Sugar, Garlic",
                Steps = "1. Soak rice noodles in warm water 30 minutes.\n2. Press and cube tofu, then pan-fry until golden.\n3. Scramble eggs in the same pan.\n4. Add garlic, then noodles.\n5. Toss with tamarind, fish sauce, and sugar mixture.\n6. Add bean sprouts and tofu.\n7. Serve with crushed peanuts and lime wedges." },
            new() { Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Ingredients = "Ground beef, Corn tortillas, Onion, Cilantro, Lime, Cumin, Chili powder, Salsa, Avocado",
                Steps = "1. Season beef with cumin and chili powder.\n2. Brown beef in a skillet.\n3. Warm tortillas on a dry griddle.\n4. Dice onion and chop cilantro.\n5. Assemble tacos with beef, onion, cilantro.\n6. Top with salsa and sliced avocado.\n7. Squeeze lime over top." },
            new() { Id = 6, Title = "Guacamole", Category = "Mexican",
                Ingredients = "Avocados, Lime juice, Red onion, Jalapeño, Cilantro, Tomato, Salt",
                Steps = "1. Halve and pit avocados.\n2. Mash to desired consistency.\n3. Finely dice onion, jalapeño, and tomato.\n4. Mix all ingredients together.\n5. Season with salt and lime juice.\n6. Serve with tortilla chips." },
            new() { Id = 7, Title = "Miso Ramen", Category = "Japanese",
                Ingredients = "Ramen noodles, Miso paste, Pork belly, Soft-boiled egg, Corn, Green onions, Sesame oil, Chicken broth",
                Steps = "1. Simmer chicken broth with miso paste.\n2. Slice and sear pork belly.\n3. Cook ramen noodles according to package.\n4. Soft-boil eggs (6.5 minutes).\n5. Assemble bowls: noodles, broth, pork.\n6. Top with halved egg, corn, green onions.\n7. Drizzle with sesame oil." },
            new() { Id = 8, Title = "Chocolate Lava Cake", Category = "Desserts",
                Ingredients = "Dark chocolate, Butter, Eggs, Sugar, Flour, Vanilla extract",
                Steps = "1. Preheat oven to 425°F.\n2. Melt chocolate and butter together.\n3. Whisk eggs and sugar until thick.\n4. Fold chocolate mixture into eggs.\n5. Add flour and vanilla, mix gently.\n6. Pour into greased ramekins.\n7. Bake 12-14 minutes (edges set, center soft).\n8. Invert onto plates and serve immediately." },
        };
        _nextId = _recipes.Max(r => r.Id) + 1;
    }

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        if (stars < 1 || stars > 5) return;
        if (!_ratings.ContainsKey(recipeId))
            _ratings[recipeId] = new List<int>();
        _ratings[recipeId].Add(stars);
    }

    public (double Average, int Count) GetRating(int recipeId)
    {
        if (!_ratings.TryGetValue(recipeId, out var ratings) || ratings.Count == 0)
            return (0, 0);
        return (ratings.Average(), ratings.Count);
    }
}

