@using RecipeShare.Services
@rendermode InteractiveServer
@inject RecipeService RecipeService

<div class="d-inline-block">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= selectedRating ? "selected" : "")"
              @onclick="() => Rate(star)"
              role="button"
              title="Rate @star star(s)">
            @(star <= selectedRating ? "★" : "☆")
        </span>
    }
    @if (ratingCount > 0)
    {
        <span class="ms-2 text-muted small">@averageRating.ToString("F1") avg (@ratingCount ratings)</span>
    }
    @if (justRated)
    {
        <span class="ms-2 text-success small">Thanks for rating!</span>
    }
</div>

<style>
    .star {
        font-size: 1.5rem;
        cursor: pointer;
        color: #ccc;
        transition: color 0.2s;
    }
    .star:hover,
    .star.selected {
        color: #ffc107;
    }
</style>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int selectedRating;
    private double averageRating;
    private int ratingCount;
    private bool justRated;

    protected override void OnParametersSet()
    {
        LoadRating();
    }

    private void Rate(int stars)
    {
        selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        justRated = true;
        LoadRating();
    }

    private void LoadRating()
    {
        var (avg, count) = RecipeService.GetRating(RecipeId);
        averageRating = avg;
        ratingCount = count;
    }
}

