@page "/submit"
@using RecipeShare.Services
@rendermode InteractiveServer
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>📝 Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Thank you!</strong> Your recipe "@Model.Title" has been submitted successfully.
        <a href="/recipe/@submittedId">View your recipe</a>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="Model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => Model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="Model.Category" class="form-select">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Thai">Thai</option>
                <option value="Mexican">Mexican</option>
                <option value="Japanese">Japanese</option>
                <option value="Desserts">Desserts</option>
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => Model.Category" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" @bind-Value="Model.Ingredients" class="form-control" rows="4"
                placeholder="List ingredients separated by commas (e.g., Flour, Sugar, Butter, Eggs)" />
            <ValidationMessage For="() => Model.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" @bind-Value="Model.Steps" class="form-control" rows="6"
                placeholder="Write each step on a new line (e.g., 1. Preheat oven to 350°F.)" />
            <ValidationMessage For="() => Model.Steps" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
        <a href="/" class="btn btn-link">Cancel</a>
    </EditForm>
}

@code {
    private RecipeFormModel Model { get; set; } = new();
    private bool submitted;
    private int submittedId;

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = Model.Title,
            Category = Model.Category,
            Ingredients = Model.Ingredients,
            Steps = Model.Steps
        };
        RecipeService.AddRecipe(recipe);
        submittedId = recipe.Id;
        submitted = true;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required.")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required.")]
        public string Steps { get; set; } = string.Empty;
    }
}

@using RecipeShare.Services
@rendermode InteractiveServer
@inject RecipeService RecipeService

<div class="d-inline-block">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= selectedRating ? "selected" : "")"
              @onclick="() => Rate(star)"
              role="button"
              title="Rate @star star(s)">
            @(star <= selectedRating ? "★" : "☆")
        </span>
    }
    @if (ratingCount > 0)
    {
        <span class="ms-2 text-muted small">@averageRating.ToString("F1") avg (@ratingCount ratings)</span>
    }
    @if (justRated)
    {
        <span class="ms-2 text-success small">Thanks for rating!</span>
    }
</div>

<style>
    .star {
        font-size: 1.5rem;
        cursor: pointer;
        color: #ccc;
        transition: color 0.2s;
    }
    .star:hover,
    .star.selected {
        color: #ffc107;
    }
</style>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int selectedRating;
    private double averageRating;
    private int ratingCount;
    private bool justRated;

    protected override void OnParametersSet()
    {
        LoadRating();
    }

    private void Rate(int stars)
    {
        selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        justRated = true;
        LoadRating();
    }

    private void LoadRating()
    {
        var (avg, count) = RecipeService.GetRating(RecipeId);
        averageRating = avg;
        ratingCount = count;
    }
}

